// lib/documentation/articles.ts
import 'server-only';

export function getArticleBySlug(slug: string) {
  // Only runs on server: database queries, file I/O
  const article = readJsonFile(`data/articles/${slug}.json`);
  return parseArticle(article); // TypeScript validates
}

// lib/schemas/article-schema.ts
import { z } from 'zod';

export const ArticleSchema = z.object({
  meta: z.object({
    slug: z.string(),
    title: z.string(),
  }),
  blocks: z.array(BlockUnionSchema),
});

export type Article = z.infer<typeof ArticleSchema>;
